import{_ as a,H as o,f as n,i as s}from"./chunks/framework.DbTCwA-u.js";const g=JSON.parse('{"title":"Resolución de Problemas","description":"Problemas comunes y soluciones al usar EligiusNametag.","frontmatter":{"title":"Resolución de Problemas","description":"Problemas comunes y soluciones al usar EligiusNametag."},"headers":[],"relativePath":"es/troubleshooting.md","filePath":"es/troubleshooting.md"}'),r={name:"es/troubleshooting.md"};function l(i,e,t,d,c,u){return o(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="resolucion-de-problemas-troubleshooting" tabindex="-1">Resolución de Problemas (Troubleshooting) <a class="header-anchor" href="#resolucion-de-problemas-troubleshooting" aria-label="Permalink to &quot;Resolución de Problemas (Troubleshooting)&quot;">​</a></h1><p>¿Tienes algún problema con EligiusNametag? Revisa estas soluciones comunes:</p><h3 id="_1-el-nametag-no-aparece-encima-del-jugador" tabindex="-1">1. El Nametag no aparece encima del jugador <a class="header-anchor" href="#_1-el-nametag-no-aparece-encima-del-jugador" aria-label="Permalink to &quot;1. El Nametag no aparece encima del jugador&quot;">​</a></h3><ul><li><strong>¿Tienes ProtocolLib instalado?</strong> Nuestro plugin depende estrictamente de inyección de paquetes para que los nametags floten suavemente sin causar lag.</li><li><strong>¿Tienes PlaceholderAPI instalado?</strong> Si usas variables como <code>%vault_rank%</code> y no tienes PAPI, el texto puede fallar en renderizarse.</li></ul><h3 id="_2-error-de-database-connection-closed" tabindex="-1">2. Error de &quot;Database Connection Closed&quot; <a class="header-anchor" href="#_2-error-de-database-connection-closed" aria-label="Permalink to &quot;2. Error de &quot;Database Connection Closed&quot;&quot;">​</a></h3><ul><li>Esto ha sido <strong>solucionado en versiones recientes</strong>. Asegúrate de estar corriendo la última versión <code>v1.x.x</code> o superior. Si usas <strong>MySQL</strong>, verifica que la IP y las credenciales en <code>config.yml</code> sean las correctas. De lo contrario, usa <code>SQLITE</code> local.</li></ul><h3 id="_3-advertencias-de-viaversion-en-la-consola" tabindex="-1">3. Advertencias de ViaVersion en la Consola <a class="header-anchor" href="#_3-advertencias-de-viaversion-en-la-consola" aria-label="Permalink to &quot;3. Advertencias de ViaVersion en la Consola&quot;">​</a></h3><p>Si usas ViaVersion para permitir que jugadores con la 1.20 entren a tu servidor 1.21+, podrías ver mensajes sobre <em>Metadata</em> y <em>Protocol Versions</em>.</p><ul><li><strong>Causa:</strong> El cliente antiguo (ej. 1.20.2) no tiene el código nativo para procesar bien entidades grandes de <code>TEXT_DISPLAY</code>.</li><li><strong>Solución:</strong> Recomendamos encarecidamente que exijas versiones 1.21+ para la visualización perfecta de hologramas, o ignores la advertencia si el jugador no presenta crasheos visuales.</li></ul><h3 id="_4-enametag-lang-no-actualiza-el-mensaje-de-ayuda" tabindex="-1">4. /enametag lang no actualiza el mensaje de ayuda <a class="header-anchor" href="#_4-enametag-lang-no-actualiza-el-mensaje-de-ayuda" aria-label="Permalink to &quot;4. /enametag lang no actualiza el mensaje de ayuda&quot;">​</a></h3><p>Al usar <code>/enametag lang en</code>, el plugin lee de <code>lang/en.yml</code>. Si notas que alguna traducción está vacía o un comando se comporta raro, puedes borrar la carpeta <code>lang/</code> en tu directorio de plugins para que EligiusNametag la re-genere limpiamente con los últimos estándares.</p>',11)])])}const p=a(r,[["render",l]]);export{g as __pageData,p as default};
